-- ============================================================
-- BUU Exchange - เพิ่มระบบยืนยันแลกสำเร็จ + รีวิว + ร้องเรียนแนบหลักฐาน
-- (เพิ่มภายหลังจาก dump เดิม)
-- ============================================================

-- 1) ยืนยันแลกเปลี่ยนสำเร็จ (2 ฝ่ายกดยืนยัน) บนตาราง exchange_requests
ALTER TABLE `exchange_requests`
  ADD COLUMN `owner_confirmed` TINYINT(1) NOT NULL DEFAULT 0 AFTER `status`,
  ADD COLUMN `requester_confirmed` TINYINT(1) NOT NULL DEFAULT 0 AFTER `owner_confirmed`,
  ADD COLUMN `owner_confirmed_at` DATETIME NULL AFTER `requester_confirmed`,
  ADD COLUMN `requester_confirmed_at` DATETIME NULL AFTER `owner_confirmed_at`,
  ADD COLUMN `completed_at` DATETIME NULL AFTER `requester_confirmed_at`;

-- 2) รีวิวหลังแลกเปลี่ยนสำเร็จ (ให้คะแนน 3 ด้าน + คอมเมนต์)
CREATE TABLE IF NOT EXISTS `exchange_reviews` (
  `id` INT(11) NOT NULL AUTO_INCREMENT,
  `request_id` INT(11) NOT NULL,
  `reviewer_user_id` INT(11) NOT NULL,
  `reviewed_user_id` INT(11) NOT NULL,
  `punctuality` TINYINT(1) NOT NULL,
  `accuracy` TINYINT(1) NOT NULL,
  `politeness` TINYINT(1) NOT NULL,
  `comment` TEXT NULL,
  `created_at` DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uniq_review_once` (`request_id`, `reviewer_user_id`),
  KEY `idx_reviewed_user` (`reviewed_user_id`),
  CONSTRAINT `fk_exchange_reviews_request` FOREIGN KEY (`request_id`) REFERENCES `exchange_requests` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_exchange_reviews_reviewer` FOREIGN KEY (`reviewer_user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_exchange_reviews_reviewed` FOREIGN KEY (`reviewed_user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
);

-- 3) ร้องเรียน + แนบหลักฐาน + ปิดเคสโดยแอดมิน
ALTER TABLE `item_complaints`
  ADD COLUMN `evidence_text` TEXT NULL AFTER `reason`,
  ADD COLUMN `evidence_image_url` TEXT NULL AFTER `evidence_text`,
  ADD COLUMN `status` ENUM('open','closed') NOT NULL DEFAULT 'open' AFTER `evidence_image_url`,
  ADD COLUMN `admin_note` TEXT NULL AFTER `status`,
  ADD COLUMN `closed_by_admin_id` INT(11) NULL AFTER `admin_note`,
  ADD COLUMN `closed_at` DATETIME NULL AFTER `closed_by_admin_id`;

ALTER TABLE `item_complaints`
  ADD CONSTRAINT `fk_item_complaints_closed_by_admin` FOREIGN KEY (`closed_by_admin_id`) REFERENCES `users` (`id`) ON DELETE SET NULL;

-- 4) Support: นักศึกษาจบเคส + เลือกกดไลก์แอดมินได้ + อัปเดตสถิติแอดมิน
ALTER TABLE `support_conversations`
  ADD COLUMN `closed_by_student_email` VARCHAR(255) NULL AFTER `closed_at`,
  ADD COLUMN `student_liked_admin` TINYINT(1) NOT NULL DEFAULT 0 AFTER `closed_by_student_email`,
  ADD COLUMN `liked_at` DATETIME NULL AFTER `student_liked_admin`;

ALTER TABLE `users`
  ADD COLUMN `admin_likes_received` INT(11) NOT NULL DEFAULT 0 AFTER `admin_success_cases`;
